// Import required modules
const cron = require('node-cron');
const mongoose = require('mongoose');
const Task = require('../models/Task'); // Mô hình Task
const NotificationLog = require('../models/NotificationLog'); // Mô hình NotificationLog

/**
 * Scheduling Engine Class - Quản lý và lên lịch thông báo.
 */
class SchedulingEngine {
  constructor() {
    this.scheduleTasks();
  }

  /**
   * Function to schedule tasks based on recurrence.
   */
  scheduleTasks() {
    cron.schedule('* * * * *', async () => { // Chạy mỗi phút
      const now = new Date();
      const tasks = await this.getDueTasks(now);
      tasks.forEach(task => {
        this.notifyAssignees(task);
      });
    });
  }

  /**
   * Fetch tasks that are due for notification.
   * @param {Date} currentTime - Thời gian hiện tại.
   * @returns {Array} tasks - Danh sách các task.
   */
  async getDueTasks(currentTime) {
    // Tìm các task có thời gian hiển thị đã đến hạn
    return await Task.find({
      'recurrence.time': this.formatTime(currentTime),
      'status': 'active'
    });
  }

  /**
   * Notify assignees of the task.
   * @param {Object} task - Task object to notify.
   */
  async notifyAssignees(task) {
    const notificationMessage = `Task: ${task.title} is due now!`; // Thông điệp thông báo
    // Logic gửi thông báo đến assignees qua Telegram (giả định sử dụng Telegraf)
    // await telegrafBot.sendMessage(task.assignees, notificationMessage);
    console.log(`Notification sent for task: ${task.title}`);

    // Log thông báo vào cơ sở dữ liệu
    await this.logNotification(task.id);
  }

  /**
   * Log the notification in the database.
   * @param {string} taskId - ID của task.
   */
  async logNotification(taskId) {
    await NotificationLog.create({
      taskId: taskId,
      sentAt: new Date(),
      status: 'success',
      retryCount: 0
    });
  }

  /**
   * Convert current time to the formatted string for matching.
   * @param {Date} date - Thời gian hiện tại.
   * @returns {string} formattedTime - Thời gian đã định dạng.
   */
  formatTime(date) {
    // Định dạng thời gian theo chuẩn HH:mm
    return `${date.getHours()}:${date.getMinutes()}`;
  }
}

// Khởi tạo Scheduling Engine
new SchedulingEngine();

// Export SchedulingEngine cho việc sử dụng khác nếu cần
module.exports = SchedulingEngine;
